// Ringed Planet — vivid Jupiter/Saturn-inspired gas giant with dramatic banded
// atmosphere and multi-color ring system. Eight latitude bands cycle through
// rich oranges, burnt ochres, and warm browns. Five concentric ring bands span
// from rusty brown through icy bright white to wispy outer gray. A raised oval
// Great Red Spot storm marks the planet surface. The inner ring edge welds into
// the planet equator so the whole assembly is ONE connected manifold.
//
// Z-up, mm. Each band is a hemisphere shell slice — no overlapping slabs,
// so band boundaries are clean with no double-triangle artifacts.

const { Manifold } = api;

const p = api.params({
  planetR:  { type: 'number', default: 20,   min: 12, max: 30, step: 1,    unit: 'mm', label: 'Planet radius' },
  ringSpan: { type: 'number', default: 2.45, min: 1.6, max: 3, step: 0.05, label: 'Ring outer (×R)' },
  bands:    { type: 'int',    default: 8,    min: 4,  max: 9,               label: 'Latitude bands' },
  tilt:     { type: 'number', default: 22,   min: 0,  max: 35, step: 1,    unit: '°', label: 'Axial tilt' },
  spot:     { type: 'boolean', default: true, label: 'Great Red Spot' },
});

const Rp = p.planetR;

// ---------------------------------------------------------------------------
// 1. Planet latitude bands — rich Jupiter palette cycling pole-to-equator
// ---------------------------------------------------------------------------
const BAND_COLORS = [
  '#ffe4b5',  // 0 — moccasin polar cap (warm cream)
  '#b8430a',  // 1 — deep rusty-orange belt
  '#f5d08a',  // 2 — golden cream zone
  '#7a3010',  // 3 — very deep mahogany belt
  '#f0a050',  // 4 — vivid warm orange equatorial zone (widest)
  '#c05010',  // 5 — bold burnt-orange belt
  '#fce8b0',  // 6 — pale golden zone
  '#9b3d15',  // 7 — rich sienna belt
  '#ffe0a0',  // 8 — warm ivory polar cap
];

// Non-uniform band heights: equatorial band (#4) is wider, polar bands narrower.
const allEdges = [-1.0, -0.78, -0.54, -0.28, -0.06, 0.18, 0.42, 0.64, 1.0];

const nBands = Math.min(p.bands, allEdges.length - 1);
const bandEdges = nBands === allEdges.length - 1
  ? allEdges
  : Array.from({ length: nBands + 1 }, (_, i) => -1 + 2 * i / nBands);

// Build each band as: (full sphere) minus (all other bands' slabs), labeled uniquely.
// Approach: intersect a FRESH sphere with EXACT (non-overlapping) slab for each band.
// No OVER overlap — slabs tile exactly from -1 to +1 with no gaps or double coverage.
// We scale up slightly so seams are invisible, but keep each band as a distinct labeled piece.

const BIG = 4 * Rp;

const zones = [];
for (let i = 0; i < nBands; i++) {
  // Exact slab boundaries — no overlap, no gap
  const z0 = bandEdges[i]     * Rp;
  const z1 = bandEdges[i + 1] * Rp;

  // Use a fresh sphere for each band intersection to avoid shared-object issues
  const bandSphere = Manifold.sphere(Rp, 96);

  // Slab with tiny epsilon to ensure watertight union after intersect
  const slabH = (z1 - z0) + 0.01;  // 0.01mm overlap for watertight seams
  const slab = Manifold.cube([BIG, BIG, slabH], true)
    .translate([0, 0, (z0 + z1) / 2]);

  const color = BAND_COLORS[i % BAND_COLORS.length];
  zones.push(api.label(bandSphere.intersect(slab), 'band' + i, { color }));
}

const planet = Manifold.union(zones);

// ---------------------------------------------------------------------------
// 2. Great Red Spot — oval raised bump on the equatorial belt
// ---------------------------------------------------------------------------
let spot = null;

if (p.spot) {
  const bumpH   = 2.2;
  const spotRx  = 5.0;
  const spotRy  = 3.2;
  const spotLat = -0.12 * Rp;

  const spotR = Math.max(spotRx, spotRy, bumpH);
  spot = Manifold.sphere(spotR, 48)
    .scale([bumpH / spotR, spotRx / spotR, spotRy / spotR])
    .translate([Rp + bumpH * 0.35, 0, spotLat]);
  spot = api.label(spot, 'redSpot', { color: '#dd2200' });
}

// ---------------------------------------------------------------------------
// 3. Ring system — five concentric bands modeled on Saturn's ring structure
// ---------------------------------------------------------------------------
const ringInner = 0.96 * Rp;
const ringOuter = p.ringSpan * Rp;
const ringH     = 1.0;

const tube = (r, h) => Manifold.cylinder(h, r, r, 96, true);

const disk = tube(ringOuter, ringH)
  .subtract(tube(ringInner, ringH * 4));

const ringStops = [
  ringInner,
  1.22 * Rp,
  1.55 * Rp,
  2.02 * Rp,
  2.22 * Rp,
  ringOuter,
];

const RING_COLORS = [
  '#9e4a14',  // C/D ring — rusty brown
  '#4a2a0e',  // Cassini division — very dark
  '#f0f0f8',  // B ring — brilliant icy white
  '#dfc060',  // A ring — warm golden yellow
  '#9a8070',  // F/G ring — warm gray-beige
];

const ringParts = [];
for (let i = 0; i < ringStops.length - 1; i++) {
  const rIn  = ringStops[i];
  const rOut = ringStops[i + 1];
  const shell = tube(rOut + 0.6, ringH * 4)
    .subtract(tube(rIn  - 0.6, ringH * 5));
  ringParts.push(
    api.label(disk.intersect(shell), 'ring' + i, { color: RING_COLORS[i] })
  );
}
const rings = Manifold.union(ringParts);

// ---------------------------------------------------------------------------
// 4. Assemble and tilt
// ---------------------------------------------------------------------------
const bodyParts = spot ? [planet, spot, rings] : [planet, rings];
const saturn = api.expectUnion(bodyParts, { expectComponents: 1 })
  .rotate([p.tilt, 0, 0]);

return saturn;
